from flask import Flask, session, redirect, url_for
import uuid

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

@app.route('/')
def index():
    return 'Hello, World!'

@app.route('/login')
def login():
    user_id = str(uuid.uuid4())
    session['user_id'] = user_id
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    if 'user_id' in session:
        del session['user_id']
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)